{
  "name": "StudySphere AI",
  "description": "An intelligent study partner similar to NotebookLM. Upload your learning materials to generate revision plans, interactive flashcards, and AI-powered quizzes to supercharge your learning."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback } from 'react';
import { Source, ActiveView, UserTier, RevisionPlan, Flashcard, QuizQuestion } from './types';
import LeftSidebar from './components/LeftSidebar';
import SourceViewer from './components/SourceViewer';
import RevisionPlanner from './components/RevisionPlanner';
import FlashcardViewer from './components/FlashcardViewer';
import QuizRunner from './components/QuizRunner';
import ChatPanel from './components/ChatPanel';
import TierModal from './components/TierModal';
import { generateRevisionPlan, generateFlashcards, generateQuiz } from './services/geminiService';

export default function App() {
  const [sources, setSources] = useState<Source[]>([]);
  const [selectedSource, setSelectedSource] = useState<Source | null>(null);
  const [activeView, setActiveView] = useState<ActiveView>('source');

  const [revisionPlan, setRevisionPlan] = useState<RevisionPlan | null>(null);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  const [userTier, setUserTier] = useState<UserTier>('free');
  const [showTierModal, setShowTierModal] = useState<boolean>(false);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newSource: Source = {
          id: Date.now().toString(),
          name: file.name,
          content: e.target?.result as string,
        };
        setSources(prev => [...prev, newSource]);
        setSelectedSource(newSource);
        setActiveView('source');
        // Clear generated content when a new source is uploaded or selected
        setRevisionPlan(null);
        setFlashcards([]);
        setQuiz([]);
      };
      reader.readAsText(file);
    }
  };

  const handleSelectSource = (source: Source) => {
    setSelectedSource(source);
    setActiveView('source');
    setRevisionPlan(null);
    setFlashcards([]);
    setQuiz([]);
  };

  const handleGenerateRevisionPlan = useCallback(async () => {
    if (!selectedSource) return;
    if(userTier === 'free' && sources.length > 1) {
        setShowTierModal(true);
        return;
    }
    setIsLoading(true);
    setLoadingMessage('Crafting your revision plan...');
    try {
      const plan = await generateRevisionPlan(selectedSource.content);
      setRevisionPlan(plan);
    } catch (error) {
      console.error("Failed to generate revision plan:", error);
      alert("Sorry, I couldn't generate a revision plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, sources.length]);

  const handleGenerateFlashcards = useCallback(async () => {
    if (!selectedSource) return;
    setIsLoading(true);
    setLoadingMessage('Creating your flashcards...');
    try {
      const cards = await generateFlashcards(selectedSource.content);
      setFlashcards(cards);
    } catch (error) {
      console.error("Failed to generate flashcards:", error);
      alert("Sorry, I couldn't generate flashcards. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource]);

  const handleGenerateQuiz = useCallback(async (questionCount: number) => {
    if (!selectedSource) return;
    if (userTier === 'free' && questionCount > 5) {
      setShowTierModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Building your quiz...');
    try {
      const questions = await generateQuiz(selectedSource.content, questionCount);
      setQuiz(questions);
    } catch (error) {
      console.error("Failed to generate quiz:", error);
      alert("Sorry, I couldn't generate a quiz. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier]);

  const renderMainContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-gray-400">
          <svg className="animate-spin h-10 w-10 text-indigo-400 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-lg">{loadingMessage}</p>
        </div>
      );
    }

    if (!selectedSource) {
      return (
        <div className="flex items-center justify-center h-full text-gray-500">
          <p className="text-xl">Upload a source document to get started.</p>
        </div>
      );
    }

    switch (activeView) {
      case 'plan':
        return <RevisionPlanner plan={revisionPlan} onGenerate={handleGenerateRevisionPlan} />;
      case 'flashcards':
        return <FlashcardViewer cards={flashcards} onGenerate={handleGenerateFlashcards} />;
      case 'quiz':
        return <QuizRunner quiz={quiz} onGenerate={handleGenerateQuiz} userTier={userTier} />;
      case 'source':
      default:
        return <SourceViewer source={selectedSource} />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-900 text-gray-100 font-sans">
      {showTierModal && <TierModal onClose={() => setShowTierModal(false)} onUpgrade={() => {setUserTier('premium'); setShowTierModal(false);}} />}
      <LeftSidebar
        sources={sources}
        onFileUpload={handleFileUpload}
        onSelectSource={handleSelectSource}
        selectedSource={selectedSource}
        activeView={activeView}
        setActiveView={setActiveView}
        userTier={userTier}
        onUpgradeClick={() => setShowTierModal(true)}
      />
      <main className="flex-grow flex flex-col md:grid md:grid-cols-3 gap-4 p-4 h-screen overflow-hidden">
        <div className="md:col-span-2 bg-gray-800 rounded-lg shadow-lg overflow-y-auto h-full p-2 md:p-6">
          {renderMainContent()}
        </div>
        <div className="bg-gray-800 rounded-lg shadow-lg flex flex-col h-full overflow-hidden">
          <ChatPanel selectedSource={selectedSource} />
        </div>
      </main>
    </div>
  );
}

export interface Source {
  id: string;
  name: string;
  content: string;
}

export type ActiveView = 'source' | 'plan' | 'flashcards' | 'quiz';

export type UserTier = 'free' | 'premium';

export interface RevisionPlanItem {
  topic: string;
  subtopics: string[];
}

export type RevisionPlan = RevisionPlanItem[];

export interface Flashcard {
  term: string;
  definition: string;
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctAnswer: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { RevisionPlan, Flashcard, QuizQuestion } from '../types';

if (!process.env.API_KEY) {
    // In a real app, you'd want to handle this more gracefully.
    // For this example, we'll throw an error if the key is missing.
    throw new Error("API_KEY environment variable not set.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function generateRevisionPlan(sourceText: string): Promise<RevisionPlan> {
    const model = "gemini-3-flash-preview";
    const prompt = `Based on the following learning material, create a structured revision plan. Break down the main topics and list key subtopics or concepts to review for each.

    Material:
    ---
    ${sourceText}
    ---

    Provide the output as a JSON array.`;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        topic: {
                            type: Type.STRING,
                            description: "The main topic or chapter to review."
                        },
                        subtopics: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING },
                            description: "A list of key subtopics, concepts, or terms under the main topic."
                        }
                    },
                    required: ["topic", "subtopics"]
                }
            }
        }
    });

    return JSON.parse(response.text);
}

export async function generateFlashcards(sourceText: string): Promise<Flashcard[]> {
    const model = "gemini-3-flash-preview";
    const prompt = `From the text provided, create a set of 10-15 flashcards. Each flashcard should have a clear term and a concise definition.

    Text:
    ---
    ${sourceText}
    ---

    Return the result as a JSON array.`;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        term: {
                            type: Type.STRING,
                            description: "The key term, concept, or question for the front of the flashcard."
                        },
                        definition: {
                            type: Type.STRING,
                            description: "The definition or answer for the back of the flashcard."
                        }
                    },
                    required: ["term", "definition"]
                }
            }
        }
    });

    return JSON.parse(response.text);
}

export async function generateQuiz(sourceText: string, questionCount: number): Promise<QuizQuestion[]> {
    const model = "gemini-3-flash-preview";
    const prompt = `Create a multiple-choice quiz with exactly ${questionCount} questions based on the provided material. For each question, provide 4 distinct options and clearly indicate the correct answer. The correct answer must be one of the options.

    Material:
    ---
    ${sourceText}
    ---

    Provide the output as a JSON array.`;

    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        question: {
                            type: Type.STRING,
                            description: "The quiz question."
                        },
                        options: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING },
                            description: "An array of 4 possible answers."
                        },
                        correctAnswer: {
                            type: Type.STRING,
                            description: "The correct answer, which must match one of the items in the 'options' array."
                        }
                    },
                    required: ["question", "options", "correctAnswer"]
                }
            }
        }
    });

    return JSON.parse(response.text);
}

export async function answerQuestionBasedOnSource(sourceText: string, question: string) {
    const model = "gemini-3-flash-preview";
    const prompt = `You are a helpful study assistant. Using the provided source material, answer the user's question. If the answer isn't in the material, say so. Keep your answers concise and directly related to the source.

    Source Material:
    ---
    ${sourceText}
    ---

    User's Question: "${question}"`;

    const response = await ai.models.generateContentStream({
        model,
        contents: prompt,
    });

    return response;
}

import React from 'react';
import { Source, ActiveView, UserTier } from '../types';

