import React from 'react';
import { Source } from '../types';

interface SourceViewerProps {
  source: Source;
}

export default function SourceViewer({ source }: SourceViewerProps) {
  return (
    <div className="h-full">
      <h2 className="text-2xl font-bold text-white mb-4 sticky top-0 bg-gray-800 py-2">{source.name}</h2>
      <div className="prose prose-invert max-w-none text-gray-300 whitespace-pre-wrap">
        {source.content}
