  .transform-style-preserve-3d { transform-style: preserve-3d; }
  .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; }
  .rotate-y-180 { transform: rotateY(180deg); }
`;
document.head.appendChild(style);

import React, { useState, useEffect } from 'react';
import { QuizQuestion, UserTier } from '../types';

interface QuizRunnerProps {
  quiz: QuizQuestion[];
  onGenerate: (questionCount: number) => void;
  userTier: UserTier;
}

export default function QuizRunner({ quiz, onGenerate, userTier }: QuizRunnerProps) {
  const [questionCount, setQuestionCount] = useState(5);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedAnswers, setSelectedAnswers] = useState<{[key: number]: string}>({});
  const [isFinished, setIsFinished] = useState(false);
  const [score, setScore] = useState(0);

  useEffect(() => {
    setCurrentIndex(0);
    setSelectedAnswers({});
    setIsFinished(false);
    setScore(0);
  }, [quiz]);

  const handleAnswerSelect = (option: string) => {
    if (isFinished) return;
    setSelectedAnswers(prev => ({ ...prev, [currentIndex]: option }));
  };

  const handleNext = () => {
    if (currentIndex < quiz.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      // Finish quiz
      let finalScore = 0;
      quiz.forEach((q, index) => {
        if (selectedAnswers[index] === q.correctAnswer) {
          finalScore++;
        }
      });
      setScore(finalScore);
      setIsFinished(true);
    }
  };

  if (quiz.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center">
        <h2 className="text-2xl font-bold text-white mb-4">Challenge yourself with a quiz.</h2>
        <p className="text-gray-400 mb-6">Generate a multiple-choice quiz based on your study material.</p>
        <div className="flex items-center space-x-4">
          <label htmlFor="question-count" className="text-gray-300">Questions:</label>
          <select 
            id="question-count"
            value={questionCount}
            onChange={(e) => setQuestionCount(Number(e.target.value))}
            className="bg-gray-700 text-white rounded-md p-2"
          >
            <option value={5}>5</option>
            <option value={10}>10 {userTier === 'free' && '(Premium)'}</option>
            <option value={15}>15 {userTier === 'free' && '(Premium)'}</option>
          </select>
        </div>
        <button
          onClick={() => onGenerate(questionCount)}
          className="mt-6 px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 transition-transform transform hover:scale-105"
        >
          Generate Quiz
        </button>
      </div>
    );
  }

  if (isFinished) {
    return (
        <div className="flex flex-col items-center justify-center h-full text-center animate-fade-in">
            <h2 className="text-4xl font-bold text-white mb-4">Quiz Complete!</h2>
            <p className="text-2xl text-indigo-400 mb-8">Your Score: {score} / {quiz.length}</p>
            <button
                onClick={() => onGenerate(quiz.length)}
                className="px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700"
            >
                Try Again
            </button>
        </div>
    );
  }

  const currentQuestion = quiz[currentIndex];

  return (
    <div className="p-4 animate-fade-in">
        <p className="text-sm text-gray-400 mb-2">Question {currentIndex + 1} of {quiz.length}</p>
        <h3 className="text-2xl font-semibold text-white mb-6">{currentQuestion.question}</h3>
        <div className="space-y-3">
            {currentQuestion.options.map((option, index) => {
                const isSelected = selectedAnswers[currentIndex] === option;
                return (
                    <button
                        key={index}
                        onClick={() => handleAnswerSelect(option)}
                        className={`w-full text-left p-4 rounded-lg border-2 transition-colors duration-200 ${
                            isSelected
                                ? 'bg-indigo-500 border-indigo-400'
                                : 'bg-gray-700 border-gray-600 hover:bg-gray-600'
                        }`}
                    >
                        {option}
                    </button>
                );
            })}
        </div>
        <div className="mt-8 flex justify-end">
            <button
                onClick={handleNext}
                disabled={!selectedAnswers[currentIndex]}
                className="px-8 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 disabled:bg-gray-500 disabled:cursor-not-allowed"
            >
                {currentIndex < quiz.length - 1 ? 'Next' : 'Finish'}
            </button>
        </div>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Source } from '../types';
import { answerQuestionBasedOnSource } from '../services/geminiService';
import { GenerateContentResponse } from '@google/genai';


interface Message {
  sender: 'user' | 'ai';
  text: string;
}

interface ChatPanelProps {
  selectedSource: Source | null;
}

export default function ChatPanel({ selectedSource }: ChatPanelProps) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(scrollToBottom, [messages]);

  useEffect(() => {
    if (selectedSource) {
      setMessages([
        { sender: 'ai', text: `Hi! I'm ready to answer questions about "${selectedSource.name}".` }
      ]);
    } else {
      setMessages([
        { sender: 'ai', text: 'Please select or upload a source to start chatting.' }
      ]);
    }
  }, [selectedSource]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || !selectedSource || isLoading) return;

    const userMessage: Message = { sender: 'user', text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const stream = await answerQuestionBasedOnSource(selectedSource.content, input);
      let aiResponse = '';
      setMessages(prev => [...prev, { sender: 'ai', text: '' }]);

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse
        aiResponse += c.text;
        setMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1].text = aiResponse;
          return newMessages;
        });
      }

    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { sender: 'ai', text: "Sorry, I encountered an error. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full p-4">
      <h2 className="text-lg font-bold text-white mb-4 border-b border-gray-700 pb-2">AI Assistant</h2>
      <div className="flex-grow overflow-y-auto mb-4 pr-2 space-y-4">
        {messages.map((msg, index) => (
          <div key={index} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-xs md:max-w-md lg:max-w-lg px-4 py-2 rounded-xl ${msg.sender === 'user' ? 'bg-indigo-600 text-white' : 'bg-gray-600 text-gray-200'}`}>
              <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && messages[messages.length-1].sender === 'user' && (
            <div className="flex justify-start">
                <div className="bg-gray-600 text-gray-200 px-4 py-2 rounded-xl">
                    <div className="flex items-center space-x-2">
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse"></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse delay-75"></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse delay-150"></div>
                    </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>
      <form onSubmit={handleSendMessage} className="flex items-center border-t border-gray-700 pt-4">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder={selectedSource ? "Ask a question..." : "Select a source first"}
          disabled={!selectedSource || isLoading}
          className="flex-grow bg-gray-700 text-white rounded-l-md p-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50"
        />
        <button type="submit" disabled={!selectedSource || isLoading} className="bg-indigo-600 text-white p-3 rounded-r-md hover:bg-indigo-700 disabled:bg-gray-500">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>
        </button>
      </form>
    </div>
  );
}

