import React, { useState } from 'react';
import { AiSearchResult, TrustedSource } from '../types';

interface AiSearchProps {
  onSearch: (query: string, trustedSources: TrustedSource[]) => void;
  searchResult: AiSearchResult | null;
}

const sourceOptions: TrustedSource[] = ['Britannica', 'Khan Academy', 'Wikipedia'];

export default function AiSearch({ onSearch, searchResult }: AiSearchProps) {
  const [query, setQuery] = useState('');
  const [selectedSources, setSelectedSources] = useState<TrustedSource[]>([]);

  const handleSourceToggle = (source: TrustedSource) => {
    setSelectedSources(prev => 
      prev.includes(source) 
        ? prev.filter(s => s !== source)
        : [...prev, source]
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      onSearch(query.trim(), selectedSources);
    }
  };

  return (
    <div className="flex flex-col h-full w-full max-w-4xl mx-auto px-4">
      <div className="pt-8 pb-6">
        <h2 className="text-3xl font-bold text-gray-900 dark:text-white text-center mb-2">AI Search Engine</h2>
        <p className="text-gray-500 dark:text-gray-400 text-center">Find explanations for complex topics, backed by web sources.</p>
        <form onSubmit={handleSubmit} className="mt-6">
          <div className="flex">
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="e.g., Explain the theory of relativity"
              className="w-full bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white rounded-l-lg p-4 text-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button type="submit" className="bg-indigo-600 text-white px-6 rounded-r-lg font-semibold hover:bg-indigo-700">
              Search
            </button>
          </div>
          <div className="mt-4 flex items-center justify-center space-x-2 sm:space-x-4">
            <span className="text-sm font-medium text-gray-500 dark:text-gray-400">Trusted Sources:</span>
            {sourceOptions.map(source => (
              <button
                key={source}
                type="button"
                onClick={() => handleSourceToggle(source)}
                className={`px-3 py-1 text-sm rounded-full transition-colors duration-200 ${
                  selectedSources.includes(source)
                    ? 'bg-indigo-600 text-white'
                    : 'bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-600'
                }`}
              >
                {source}
              </button>
            ))}
          </div>
        </form>
      </div>
      <div className="flex-grow overflow-y-auto">
        {searchResult ? (
          <div className="animate-fade-in space-y-6 pb-8">
            <div className="prose prose-lg prose-gray dark:prose-invert max-w-none text-gray-700 dark:text-gray-300">
              <p>{searchResult.summary}</p>
            </div>
            {searchResult.sources.length > 0 && (
              <div>
                <h3 className="text-lg font-semibold text-gray-600 dark:text-gray-400 mb-3">Sources:</h3>
                <div className="space-y-2">
                  {searchResult.sources.map((source, index) => (
                    <a
                      key={index}
                      href={source.uri}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="block p-3 bg-gray-100 dark:bg-gray-700 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors"
                    >
                      <p className="font-semibold text-indigo-600 dark:text-indigo-300 truncate">{source.title}</p>
                      <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{source.uri}</p>
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <div className="flex items-center justify-center h-full text-gray-500 dark:text-gray-500">
            <p>Your search results will appear here.</p>
          </div>
        )}
      </div>
    </div>
  );
}

