    let fullQuery = `Provide a concise and informative answer to the following query, based on a web search: "${query}"`;

    if (trustedSources.length > 0) {
        const siteFilters = trustedSources.map(source => `site:${trustedSourceDomains[source]}`).join(' OR ');
        fullQuery += ` Prioritize information from these sources: ${siteFilters}`;
    }

    const response = await ai.models.generateContent({
        model,
        contents: fullQuery,
        config: {
            tools: [{googleSearch: {}}],
        },
    });

    const summary = response.text || "No summary available.";

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
