    const response = await ai.models.generateContent({
        model,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        topic: {
                            type: Type.STRING,
                            description: "The main topic or chapter to review."
                        },
                        subtopics: {
                            type: Type.ARRAY,
                            items: { type: Type.STRING },
                            description: "A list of key subtopics, concepts, or terms under the main topic."
