      <div className="flex-grow overflow-y-auto">
        {searchResult ? (
          <div className="animate-fade-in space-y-6 pb-8">
            <div className="prose prose-lg prose-gray dark:prose-invert max-w-none text-gray-700 dark:text-gray-300">
              <p>{searchResult.summary}</p>
            </div>
            {searchResult.sources.length > 0 && (
              <div>
                <h3 className="text-lg font-semibold text-gray-600 dark:text-gray-400 mb-3">Sources:</h3>
                <div className="space-y-2">
