export default function LeftSidebar({
  sources,
  onFileUpload,
  onSelectSource,
  selectedSource,
  activeView,
  setActiveView,
  userTier,
  onUpgradeClick,
  theme,
  toggleTheme,
  isAuthenticated,
  onLoginClick,
  onLogout,
