  return (
    <aside className="w-80 bg-white dark:bg-gray-800 p-4 flex flex-col h-full border-r border-gray-200 dark:border-gray-700 shadow-xl">
      <div className="flex items-center mb-6">
        <svg className="w-8 h-8 text-indigo-500 dark:text-indigo-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" />
        </svg>
        <h1 className="text-xl font-bold ml-2 text-gray-900 dark:text-white">StudySphere AI</h1>
      </div>

      <div className="mb-4">
        <label
          htmlFor="file-upload"
          onClick={handleAddSourceClick}
          className="w-full text-center px-4 py-2 bg-indigo-600 text-white rounded-md cursor-pointer hover:bg-indigo-700 transition-colors duration-200 block font-semibold"
        >
          + Add Source
        </label>
        <input id="file-upload" type="file" className="hidden" onChange={onFileUpload} accept=".txt,.md" />
      </div>

      <div className="flex-grow overflow-y-auto pr-2 -mr-2">
        <h2 className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-2">Sources</h2>
        <ul className="space-y-1">
          {sources.map(source => (
            <li key={source.id}>
              <button
                onClick={() => onSelectSource(source)}
                className={`w-full text-left px-3 py-2 rounded-md text-sm transition-colors duration-200 truncate ${
                  selectedSource?.id === source.id ? 'bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white font-semibold' : 'text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
                }`}
              >
                {source.name}
              </button>
            </li>
          ))}
        </ul>
      </div>

      <div className="mt-auto">
        <h2 className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-2">Tools</h2>
        <nav className="space-y-2">
            <NavItem icon={<SearchIcon />} label="AI Search" isActive={activeView === 'search'} onClick={handleSearchClick} isPremium={!isAuthenticated || userTier === 'free'} />
            <NavItem icon={<DocIcon />} label="View Source" isActive={activeView === 'source'} onClick={() => setActiveView('source')} disabled={!selectedSource} />
            <NavItem icon={<PlanIcon />} label="Revision Plan" isActive={activeView === 'plan'} onClick={() => setActiveView('plan')} disabled={!selectedSource} />
            <NavItem icon={<FlashcardIcon />} label="Flashcards" isActive={activeView === 'flashcards'} onClick={() => setActiveView('flashcards')} disabled={!selectedSource} />
            <NavItem icon={<QuizIcon />} label="AI Quiz" isActive={activeView === 'quiz'} onClick={() => setActiveView('quiz')} disabled={!selectedSource} />
        </nav>
        <div className="mt-6 pt-4 border-t border-gray-200 dark:border-gray-700">
            {isAuthenticated && (
              <div className="bg-gray-200 dark:bg-gray-700 rounded-lg p-3 text-center flex-grow mb-4">
                  <p className="text-sm font-medium text-gray-900 dark:text-white">
                      Tier: <span className={`font-bold ${userTier === 'premium' ? 'text-yellow-600 dark:text-yellow-400' : 'text-gray-600 dark:text-gray-300'}`}>{userTier.charAt(0).toUpperCase() + userTier.slice(1)}</span>
                  </p>
                  {userTier === 'free' && (
                      <button onClick={onUpgradeClick} className="mt-2 w-full text-sm bg-yellow-500 text-gray-900 font-bold py-1 px-3 rounded-md hover:bg-yellow-400 transition-colors duration-200">
                          Upgrade Now
                      </button>
                  )}
              </div>
            )}
            <div className="flex items-center justify-between">
                {isAuthenticated ? (
                  <button onClick={onLogout} className="flex items-center text-sm text-gray-500 dark:text-gray-400 hover:text-red-500 dark:hover:text-red-400 font-semibold transition-colors">
                      <LogoutIcon />
                      <span className="ml-2">Logout</span>
                  </button>
                ) : (
                  <button onClick={onLoginClick} className="flex-grow flex items-center justify-center text-sm text-white bg-indigo-600 hover:bg-indigo-700 font-semibold transition-colors py-2 px-4 rounded-md">
                      <LoginIcon />
                      <span className="ml-2">Login / Sign Up</span>
                  </button>
                )}
                <button onClick={toggleTheme} className="p-2 ml-4 rounded-full text-gray-500 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors">
                    {theme === 'light' ? <MoonIcon /> : <SunIcon />}
                </button>
            </div>
        </div>
      </div>
    </aside>
  );
}

