import React, { useState, useEffect } from 'react';
import { QuizQuestion, UserTier } from '../types';

interface QuizRunnerProps {
  quiz: QuizQuestion[];
  onGenerate: (questionCount: number) => void;
  userTier: UserTier;
  isAuthenticated: boolean;
}

export default function QuizRunner({ quiz, onGenerate, userTier, isAuthenticated }: QuizRunnerProps) {
  const [questionCount, setQuestionCount] = useState(5);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedAnswers, setSelectedAnswers] = useState<{[key: number]: string}>({});
  const [isFinished, setIsFinished] = useState(false);
  const [score, setScore] = useState(0);

  useEffect(() => {
    setCurrentIndex(0);
    setSelectedAnswers({});
    setIsFinished(false);
    setScore(0);
  }, [quiz]);

  const handleAnswerSelect = (option: string) => {
    if (isFinished) return;
    setSelectedAnswers(prev => ({ ...prev, [currentIndex]: option }));
  };

  const handleNext = () => {
    if (currentIndex < quiz.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      // Finish quiz
      let finalScore = 0;
      quiz.forEach((q, index) => {
        if (selectedAnswers[index] === q.correctAnswer) {
          finalScore++;
        }
      });
      setScore(finalScore);
      setIsFinished(true);
    }
  };

  if (quiz.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">Challenge yourself with a quiz.</h2>
        <p className="text-gray-500 dark:text-gray-400 mb-6">Generate a multiple-choice quiz based on your study material.</p>
        <div className="flex items-center space-x-4">
          <label htmlFor="question-count" className="text-gray-600 dark:text-gray-300">Questions:</label>
          <select 
            id="question-count"
            value={questionCount}
            onChange={(e) => setQuestionCount(Number(e.target.value))}
            className="bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white rounded-md p-2"
          >
            <option value={5}>5</option>
            <option value={10}>10 {isAuthenticated && userTier === 'free' && '(Premium)'}</option>
            <option value={15}>15 {isAuthenticated && userTier === 'free' && '(Premium)'}</option>
          </select>
        </div>
        <button
          onClick={() => onGenerate(questionCount)}
          className="mt-6 px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 transition-transform transform hover:scale-105"
        >
          Generate Quiz
        </button>
      </div>
    );
  }

  if (isFinished) {
    return (
        <div className="flex flex-col items-center justify-center h-full text-center animate-fade-in">
            <h2 className="text-4xl font-bold text-gray-900 dark:text-white mb-4">Quiz Complete!</h2>
            <p className="text-2xl text-indigo-500 dark:text-indigo-400 mb-8">Your Score: {score} / {quiz.length}</p>
            <button
                onClick={() => onGenerate(quiz.length)}
                className="px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700"
            >
                Try Again
            </button>
        </div>
    );
  }

  const currentQuestion = quiz[currentIndex];

  return (
    <div className="p-4 animate-fade-in">
        <p className="text-sm text-gray-500 dark:text-gray-400 mb-2">Question {currentIndex + 1} of {quiz.length}</p>
        <h3 className="text-2xl font-semibold text-gray-900 dark:text-white mb-6">{currentQuestion.question}</h3>
        <div className="space-y-3">
            {currentQuestion.options.map((option, index) => {
                const isSelected = selectedAnswers[currentIndex] === option;
                return (
                    <button
                        key={index}
                        onClick={() => handleAnswerSelect(option)}
                        className={`w-full text-left p-4 rounded-lg border-2 transition-colors duration-200 ${
                            isSelected
                                ? 'bg-indigo-500 border-indigo-400 text-white'
                                : 'bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 hover:bg-gray-200 dark:hover:bg-gray-600'
                        }`}
                    >
                        {option}
                    </button>
                );
            })}
        </div>
        <div className="mt-8 flex justify-end">
            <button
                onClick={handleNext}
                disabled={!selectedAnswers[currentIndex]}
                className="px-8 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 disabled:bg-gray-400 dark:disabled:bg-gray-500 disabled:cursor-not-allowed"
            >
                {currentIndex < quiz.length - 1 ? 'Next' : 'Finish'}
            </button>
        </div>
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { Source } from '../types';
import { answerQuestionBasedOnSource } from '../services/geminiService';
import { GenerateContentResponse } from '@google/genai';


interface Message {
  sender: 'user' | 'ai';
  text: string;
}

interface ChatPanelProps {
  selectedSource: Source | null;
  isAuthenticated: boolean;
}

export default function ChatPanel({ selectedSource, isAuthenticated }: ChatPanelProps) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(scrollToBottom, [messages]);

  useEffect(() => {
    if (selectedSource) {
      setMessages([
        { sender: 'ai', text: `Hi! I'm ready to answer questions about "${selectedSource.name}".` }
      ]);
    } else {
       setMessages([
        { sender: 'ai', text: isAuthenticated ? 'Please select or upload a source to start chatting.' : 'Please select a sample source to start chatting.' }
      ]);
    }
  }, [selectedSource, isAuthenticated]);

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || !selectedSource || isLoading) return;

    const userMessage: Message = { sender: 'user', text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const stream = await answerQuestionBasedOnSource(selectedSource.content, input);
      let aiResponse = '';
      setMessages(prev => [...prev, { sender: 'ai', text: '' }]);

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse
        aiResponse += c.text;
        setMessages(prev => {
          const newMessages = [...prev];
          newMessages[newMessages.length - 1].text = aiResponse;
          return newMessages;
        });
      }

    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { sender: 'ai', text: "Sorry, I encountered an error. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full p-4">
      <h2 className="text-lg font-bold text-gray-900 dark:text-white mb-4 border-b border-gray-200 dark:border-gray-700 pb-2">AI Assistant</h2>
      <div className="flex-grow overflow-y-auto mb-4 pr-2 space-y-4">
        {messages.map((msg, index) => (
          <div key={index} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-xs md:max-w-md lg:max-w-lg px-4 py-2 rounded-xl ${msg.sender === 'user' ? 'bg-indigo-600 text-white' : 'bg-gray-200 dark:bg-gray-600 text-gray-800 dark:text-gray-200'}`}>
              <p className="whitespace-pre-wrap">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && messages[messages.length-1].sender === 'user' && (
            <div className="flex justify-start">
                <div className="bg-gray-200 dark:bg-gray-600 px-4 py-2 rounded-xl">
                    <div className="flex items-center space-x-2">
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse"></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse delay-75"></div>
                        <div className="w-2 h-2 bg-gray-400 rounded-full animate-pulse delay-150"></div>
                    </div>
                </div>
            </div>
        )}
        <div ref={messagesEndRef} />
      </div>
      <form onSubmit={handleSendMessage} className="flex items-center border-t border-gray-200 dark:border-gray-700 pt-4">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder={selectedSource ? "Ask a question..." : "Select a source first"}
          disabled={!selectedSource || isLoading}
          className="flex-grow bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white rounded-l-md p-3 focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50"
        />
        <button type="submit" disabled={!selectedSource || isLoading} className="bg-indigo-600 text-white p-3 rounded-r-md hover:bg-indigo-700 disabled:bg-gray-500">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" /></svg>
        </button>
      </form>
    </div>
  );
}

import React, { useState, useCallback, useEffect } from 'react';
import { Source, ActiveView, UserTier, RevisionPlan, Flashcard, QuizQuestion, AiSearchResult, ExamBoard } from './types';
import LeftSidebar from './components/LeftSidebar';
import SourceViewer from './components/SourceViewer';
import RevisionPlanner from './components/RevisionPlanner';
import FlashcardViewer from './components/FlashcardViewer';
import QuizRunner from './components/QuizRunner';
import ChatPanel from './components/ChatPanel';
import TierModal from './components/TierModal';
import AiSearch from './components/AiSearch';
import AuthPage from './components/AuthPage';
import CheckoutPage from './components/CheckoutPage';
import { generateRevisionPlan, generateFlashcards, generateQuiz, searchWithAi } from './services/geminiService';
import { TrustedSource } from './types';
import { sampleSources } from './data/sampleSources';

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => !!localStorage.getItem('user-authenticated'));
  const [sources, setSources] = useState<Source[]>(() => {
    // In a real app, you'd fetch user-specific sources if logged in.
    // For this demo, we'll always start with the samples.
    return sampleSources;
  });
  const [selectedSource, setSelectedSource] = useState<Source | null>(sampleSources[0] || null);
  const [activeView, setActiveView] = useState<ActiveView>('source');

  const [revisionPlan, setRevisionPlan] = useState<RevisionPlan | null>(null);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [searchResult, setSearchResult] = useState<AiSearchResult | null>(null);

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  const [userTier, setUserTier] = useState<UserTier>(() => (localStorage.getItem('user-tier') as UserTier) || 'free');
  const [showTierModal, setShowTierModal] = useState<boolean>(false);
  const [showCheckout, setShowCheckout] = useState<boolean>(false);
  const [showAuthModal, setShowAuthModal] = useState<boolean>(false);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('user-tier', userTier);
  }, [userTier]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    localStorage.setItem('user-authenticated', 'true');
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserTier('free');
    // Reset to sample sources on logout
    setSources(sampleSources);
    setSelectedSource(sampleSources[0] || null);
    setActiveView('source');
    localStorage.removeItem('user-authenticated');
    localStorage.removeItem('user-tier');
    localStorage.removeItem('subscription-key');
  };

  const handleUpgradeInitiate = () => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    setShowTierModal(false);
    setShowCheckout(true);
  };

  const handlePaymentSuccess = (key: string) => {
      setUserTier('premium');
      localStorage.setItem('subscription-key', key);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    // This check is a fallback, main trigger is in LeftSidebar
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newSource: Source = {
          id: Date.now().toString(),
          name: file.name,
          content: e.target?.result as string,
        };
        // Add new source to existing list (which includes samples)
        setSources(prev => [...prev, newSource]);
        setSelectedSource(newSource);
        handleSetActiveView('source');
      };
      reader.readAsText(file);
    }
  };

  const handleSelectSource = (source: Source) => {
    setSelectedSource(source);
    handleSetActiveView('source');
  };

  const handleSetActiveView = (view: ActiveView) => {
    setRevisionPlan(null);
    setFlashcards([]);
    setQuiz([]);
    setSearchResult(null);
    setActiveView(view);
  };

  const handleGenerateRevisionPlan = useCallback(async () => {
    if (!selectedSource) return;
    if(isAuthenticated && userTier === 'free' && sources.filter(s => !s.id.startsWith('sample-')).length >= 1) {
        setShowTierModal(true);
        return;
    }
    setIsLoading(true);
    setLoadingMessage('Crafting your revision plan...');
    try {
      const plan = await generateRevisionPlan(selectedSource.content);
      setRevisionPlan(plan);
    } catch (error) {
      console.error("Failed to generate revision plan:", error);
      alert("Sorry, I couldn't generate a revision plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, sources, isAuthenticated]);

  const handleGenerateFlashcards = useCallback(async () => {
    if (!selectedSource) return;
    setIsLoading(true);
    setLoadingMessage('Creating your flashcards...');
    try {
      const cards = await generateFlashcards(selectedSource.content);
      setFlashcards(cards);
    } catch (error) {
      console.error("Failed to generate flashcards:", error);
      alert("Sorry, I couldn't generate flashcards. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource]);

  const handleGenerateQuiz = useCallback(async (questionCount: number) => {
    if (!selectedSource) return;
    if (isAuthenticated && userTier === 'free' && questionCount > 5) {
      setShowTierModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Building your quiz...');
    try {
      const questions = await generateQuiz(selectedSource.content, questionCount);
      setQuiz(questions);
    } catch (error) {
      console.error("Failed to generate quiz:", error);
      alert("Sorry, I couldn't generate a quiz. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, isAuthenticated]);

  const handleAiSearch = useCallback(async (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => {
    if (!isAuthenticated && userTier === 'free') {
      setShowAuthModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Searching the web...');
    setSearchResult(null);
    try {
      const result = await searchWithAi(query, trustedSources, examBoards);
      setSearchResult(result);
    } catch (error) {
      console.error("Failed to perform AI search:", error);
      alert("Sorry, I couldn't complete the search. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [isAuthenticated, userTier]);

  const renderMainContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-gray-500 dark:text-gray-400">
          <svg className="animate-spin h-10 w-10 text-indigo-500 dark:text-indigo-400 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-lg">{loadingMessage}</p>
        </div>
      );
    }

    if (activeView !== 'search' && !selectedSource) {
      return (
        <div className="flex items-center justify-center h-full text-gray-600 dark:text-gray-500">
          <p className="text-xl">Select or upload a source document to get started.</p>
        </div>
      );
    }

    switch (activeView) {
      case 'plan':
        return <RevisionPlanner plan={revisionPlan} onGenerate={handleGenerateRevisionPlan} />;
      case 'flashcards':
        return <FlashcardViewer cards={flashcards} onGenerate={handleGenerateFlashcards} />;
      case 'quiz':
        return <QuizRunner quiz={quiz} onGenerate={handleGenerateQuiz} userTier={userTier} isAuthenticated={isAuthenticated} />;
      case 'search':
        return <AiSearch onSearch={handleAiSearch} searchResult={searchResult} />;
      case 'source':
      default:
        return selectedSource ? <SourceViewer source={selectedSource} /> : null;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-sans">
      {showAuthModal && <AuthPage onLoginSuccess={handleLoginSuccess} onClose={() => setShowAuthModal(false)} />}
      {showTierModal && <TierModal onClose={() => setShowTierModal(false)} onUpgrade={handleUpgradeInitiate} />}
      {showCheckout && <CheckoutPage onClose={() => setShowCheckout(false)} onPaymentSuccess={handlePaymentSuccess} />}
      <LeftSidebar
        sources={sources}
        onFileUpload={handleFileUpload}
        onSelectSource={handleSelectSource}
        selectedSource={selectedSource}
        activeView={activeView}
        setActiveView={handleSetActiveView}
        userTier={userTier}
        onUpgradeClick={() => setShowTierModal(true)}
        theme={theme}
        toggleTheme={toggleTheme}
        isAuthenticated={isAuthenticated}
        onLoginClick={() => setShowAuthModal(true)}
        onLogout={handleLogout}
      />
      <main className="flex-grow flex flex-col md:grid md:grid-cols-3 gap-4 p-4 h-screen overflow-hidden">
        <div className="md:col-span-2 bg-white dark:bg-gray-800 rounded-lg shadow-lg overflow-y-auto h-full p-2 md:p-6">
          {renderMainContent()}
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg flex flex-col h-full overflow-hidden">
          <ChatPanel selectedSource={selectedSource} isAuthenticated={isAuthenticated} />
        </div>
      </main>
    </div>
  );
}

import React, { useState } from 'react';

interface CheckoutPageProps {
  onClose: () => void;
  onPaymentSuccess: (key: string) => void;
}

export default function CheckoutPage({ onClose, onPaymentSuccess }: CheckoutPageProps) {
    const [isProcessing, setIsProcessing] = useState(false);
    const [isSuccess, setIsSuccess] = useState(false);
    const [paymentMethod, setPaymentMethod] = useState('');
    const [subscriptionKey, setSubscriptionKey] = useState('');
    const [copyButtonText, setCopyButtonText] = useState('Copy');

    const handlePayment = (method: string) => {
        setIsProcessing(true);
        setPaymentMethod(method);
        // Simulate API call
        setTimeout(() => {
            const key = 'STUDY-' + Math.random().toString(36).substring(2, 8).toUpperCase() + '-' + Math.random().toString(36).substring(2, 8).toUpperCase();
            setSubscriptionKey(key);
            onPaymentSuccess(key);
            setIsProcessing(false);
            setIsSuccess(true);
        }, 2000);
    };

    const handleCopyKey = () => {
        navigator.clipboard.writeText(subscriptionKey).then(() => {
            setCopyButtonText('Copied!');
            setTimeout(() => setCopyButtonText('Copy'), 2000);
        });
    };

    const renderContent = () => {
        if (isSuccess) {
            return (
                <div className="text-center">
                    <div className="flex justify-center items-center mb-4">
                        <svg className="w-16 h-16 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                    </div>
                    <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">Upgrade Successful!</h2>
                    <p className="text-gray-500 dark:text-gray-400 mb-6">Your premium access is now active.</p>
                    <p className="text-sm text-gray-500 dark:text-gray-400 mb-2">Your Subscription Key:</p>
                    <div className="flex items-center justify-center bg-gray-200 dark:bg-gray-700 rounded-lg p-3">
                        <code className="text-sm font-mono text-gray-800 dark:text-gray-200">{subscriptionKey}</code>
                        <button onClick={handleCopyKey} className="ml-4 px-3 py-1 text-sm bg-indigo-600 text-white rounded-md hover:bg-indigo-700 w-20">{copyButtonText}</button>
                    </div>
                     <button onClick={onClose} className="mt-8 w-full bg-indigo-600 text-white font-semibold py-3 rounded-lg hover:bg-indigo-700">
                        Get Started
                    </button>
                </div>
            );
        }

        if (isProcessing) {
            return (
                <div className="text-center">
                    <div className="flex justify-center items-center mb-4">
                        <svg className="animate-spin h-8 w-8 text-indigo-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                        </svg>
                    </div>
                    <p className="text-gray-600 dark:text-gray-300">Processing with {paymentMethod}...</p>
                </div>
            );
        }

        return (
            <>
                <div className="text-center">
                    <h2 className="text-3xl font-bold text-gray-900 dark:text-white mb-2">Upgrade to Premium</h2>
                    <p className="text-gray-500 dark:text-gray-400 mb-6">Unlock all features and supercharge your studies.</p>
                </div>
                <div className="bg-white dark:bg-gray-700 rounded-lg p-6 mb-8 text-center">
                    <p className="text-lg text-gray-600 dark:text-gray-300">Total Due Today</p>
                    <p className="text-4xl font-extrabold text-indigo-600 dark:text-indigo-400">$3.00</p>
                    <p className="text-sm text-gray-500 dark:text-gray-400">Billed monthly</p>
                </div>
                <div className="space-y-3">
                    <PaymentButton method="PayPal" onClick={() => handlePayment('PayPal')} />
                    <PaymentButton method="Google Pay" onClick={() => handlePayment('Google Pay')} />
                    <PaymentButton method="Apple Pay" onClick={() => handlePayment('Apple Pay')} />
                </div>
            </>
        );
    };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 animate-fade-in">
      <div className="relative bg-gray-100 dark:bg-gray-800 rounded-xl shadow-2xl p-8 max-w-md w-full text-gray-900 dark:text-white border border-gray-300 dark:border-gray-700">
        <button onClick={onClose} className="absolute top-4 right-4 text-gray-500 hover:text-gray-800 dark:hover:text-gray-200" disabled={isProcessing || isSuccess}>
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
        {renderContent()}
      </div>
    </div>
  );
}

