import React, { useState, useCallback, useEffect } from 'react';
import { Source, ActiveView, UserTier, RevisionPlan, Flashcard, QuizQuestion, AiSearchResult, ExamBoard } from './types';
import LeftSidebar from './components/LeftSidebar';
import SourceViewer from './components/SourceViewer';
import RevisionPlanner from './components/RevisionPlanner';
import FlashcardViewer from './components/FlashcardViewer';
import QuizRunner from './components/QuizRunner';
import ChatPanel from './components/ChatPanel';
import TierModal from './components/TierModal';
import AiSearch from './components/AiSearch';
import AuthPage from './components/AuthPage';
import CheckoutPage from './components/CheckoutPage';
import { generateRevisionPlan, generateFlashcards, generateQuiz, searchWithAi } from './services/geminiService';
import { TrustedSource } from './types';
import { sampleSources } from './data/sampleSources';

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => !!localStorage.getItem('user-authenticated'));
  const [sources, setSources] = useState<Source[]>(() => {
    // In a real app, you'd fetch user-specific sources if logged in.
    // For this demo, we'll always start with the samples.
    return sampleSources;
  });
  const [selectedSource, setSelectedSource] = useState<Source | null>(sampleSources[0] || null);
  const [activeView, setActiveView] = useState<ActiveView>('source');

  const [revisionPlan, setRevisionPlan] = useState<RevisionPlan | null>(null);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [searchResult, setSearchResult] = useState<AiSearchResult | null>(null);

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  const [userTier, setUserTier] = useState<UserTier>(() => (localStorage.getItem('user-tier') as UserTier) || 'free');
  const [showTierModal, setShowTierModal] = useState<boolean>(false);
  const [showCheckout, setShowCheckout] = useState<boolean>(false);
  const [showAuthModal, setShowAuthModal] = useState<boolean>(false);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    return (localStorage.getItem('theme') as 'light' | 'dark') || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('user-tier', userTier);
  }, [userTier]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    localStorage.setItem('user-authenticated', 'true');
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserTier('free');
    // Reset to sample sources on logout
    setSources(sampleSources);
    setSelectedSource(sampleSources[0] || null);
    setActiveView('source');
    localStorage.removeItem('user-authenticated');
    localStorage.removeItem('user-tier');
    localStorage.removeItem('subscription-key');
  };

  const handleUpgradeInitiate = () => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    setShowTierModal(false);
    setShowCheckout(true);
  };

  const handlePaymentSuccess = (key: string) => {
      setUserTier('premium');
      localStorage.setItem('subscription-key', key);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    // This check is a fallback, main trigger is in LeftSidebar
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newSource: Source = {
          id: Date.now().toString(),
          name: file.name,
          content: e.target?.result as string,
        };
        // Add new source to existing list (which includes samples)
        setSources(prev => [...prev, newSource]);
        setSelectedSource(newSource);
        handleSetActiveView('source');
      };
      reader.readAsText(file);
    }
  };

  const handleSelectSource = (source: Source) => {
    setSelectedSource(source);
    handleSetActiveView('source');
  };

  const handleDeleteSource = (sourceId: string) => {
    if (selectedSource?.id === sourceId) {
      setSelectedSource(sampleSources[0] || null);
      setActiveView('source');
    }
    setSources(prevSources => prevSources.filter(source => source.id !== sourceId));
  };


  const handleSetActiveView = (view: ActiveView) => {
    setRevisionPlan(null);
    setFlashcards([]);
    setQuiz([]);
    setSearchResult(null);
    setActiveView(view);
  };

  const handleGenerateRevisionPlan = useCallback(async () => {
    if (!selectedSource) return;
    if(isAuthenticated && userTier === 'free' && sources.filter(s => !s.id.startsWith('sample-')).length >= 1) {
        setShowTierModal(true);
        return;
    }
    setIsLoading(true);
    setLoadingMessage('Crafting your revision plan...');
    try {
      const plan = await generateRevisionPlan(selectedSource.content);
      setRevisionPlan(plan);
    } catch (error) {
      console.error("Failed to generate revision plan:", error);
      alert("Sorry, I couldn't generate a revision plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, sources, isAuthenticated]);

  const handleGenerateFlashcards = useCallback(async () => {
    if (!selectedSource) return;
    setIsLoading(true);
    setLoadingMessage('Creating your flashcards...');
    try {
      const cards = await generateFlashcards(selectedSource.content);
      setFlashcards(cards);
    } catch (error) {
      console.error("Failed to generate flashcards:", error);
      alert("Sorry, I couldn't generate flashcards. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource]);

  const handleGenerateQuiz = useCallback(async (questionCount: number) => {
    if (!selectedSource) return;
    if (isAuthenticated && userTier === 'free' && questionCount > 5) {
      setShowTierModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Building your quiz...');
    try {
      const questions = await generateQuiz(selectedSource.content, questionCount);
      setQuiz(questions);
    } catch (error) {
      console.error("Failed to generate quiz:", error);
      alert("Sorry, I couldn't generate a quiz. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, isAuthenticated]);

  const handleAiSearch = useCallback(async (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => {
    if (!isAuthenticated && userTier === 'free') {
      setShowAuthModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Searching the web...');
    setSearchResult(null);
    try {
      const result = await searchWithAi(query, trustedSources, examBoards);
      setSearchResult(result);
    } catch (error) {
      console.error("Failed to perform AI search:", error);
      alert("Sorry, I couldn't complete the search. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [isAuthenticated, userTier]);

  const renderMainContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-gray-500 dark:text-gray-400">
          <svg className="animate-spin h-10 w-10 text-indigo-500 dark:text-indigo-400 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-lg">{loadingMessage}</p>
        </div>
      );
    }

    if (activeView !== 'search' && !selectedSource) {
      return (
        <div className="flex items-center justify-center h-full text-gray-600 dark:text-gray-500">
          <p className="text-xl">Select or upload a source document to get started.</p>
        </div>
      );
    }

    switch (activeView) {
      case 'plan':
        return <RevisionPlanner plan={revisionPlan} onGenerate={handleGenerateRevisionPlan} />;
      case 'flashcards':
        return <FlashcardViewer cards={flashcards} onGenerate={handleGenerateFlashcards} />;
      case 'quiz':
        return <QuizRunner quiz={quiz} onGenerate={handleGenerateQuiz} userTier={userTier} isAuthenticated={isAuthenticated} />;
      case 'search':
        return <AiSearch onSearch={handleAiSearch} searchResult={searchResult} />;
      case 'source':
      default:
        return selectedSource ? <SourceViewer source={selectedSource} /> : null;
    }
  };

  return (
    <div className="flex h-screen bg-gray-100 dark:bg-gray-900 text-gray-800 dark:text-gray-100 font-sans">
      {showAuthModal && <AuthPage onLoginSuccess={handleLoginSuccess} onClose={() => setShowAuthModal(false)} />}
      {showTierModal && <TierModal onClose={() => setShowTierModal(false)} onUpgrade={handleUpgradeInitiate} />}
      {showCheckout && <CheckoutPage onClose={() => setShowCheckout(false)} onPaymentSuccess={handlePaymentSuccess} />}
      <LeftSidebar
        sources={sources}
        onFileUpload={handleFileUpload}
        onSelectSource={handleSelectSource}
        onDeleteSource={handleDeleteSource}
        selectedSource={selectedSource}
        activeView={activeView}
        setActiveView={handleSetActiveView}
        userTier={userTier}
        onUpgradeClick={() => setShowTierModal(true)}
        theme={theme}
        toggleTheme={toggleTheme}
        isAuthenticated={isAuthenticated}
        onLoginClick={() => setShowAuthModal(true)}
        onLogout={handleLogout}
      />
      <main className="flex-grow flex flex-col md:grid md:grid-cols-3 gap-4 p-4 h-screen overflow-hidden">
        <div className="md:col-span-2 bg-white dark:bg-gray-800 rounded-lg shadow-lg overflow-y-auto h-full p-2 md:p-6">
          {renderMainContent()}
        </div>
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg flex flex-col h-full overflow-hidden">
          <ChatPanel selectedSource={selectedSource} isAuthenticated={isAuthenticated} />
        </div>
      </main>
    </div>
  );
}

import React from 'react';
import { Source, ActiveView, UserTier } from '../types';

interface LeftSidebarProps {
  sources: Source[];
  onFileUpload: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onSelectSource: (source: Source) => void;
  onDeleteSource: (sourceId: string) => void;
  selectedSource: Source | null;
  activeView: ActiveView;
  setActiveView: (view: ActiveView) => void;
  userTier: UserTier;
  onUpgradeClick: () => void;
  theme: 'light' | 'dark';
  toggleTheme: () => void;
  isAuthenticated: boolean;
  onLoginClick: () => void;
  onLogout: () => void;
}

const NavItem: React.FC<{
  icon: React.ReactElement;
  label: string;
  isActive: boolean;
  onClick: () => void;
  disabled?: boolean;
  isPremium?: boolean;
}> = ({ icon, label, isActive, onClick, disabled, isPremium = false }) => (
  <button
    onClick={onClick}
    disabled={disabled}
    className={`flex items-center w-full px-4 py-3 text-sm font-medium rounded-lg transition-colors duration-200 ${
      isActive
        ? 'bg-indigo-600 text-white'
        : 'text-gray-500 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 hover:text-gray-900 dark:hover:text-white'
    } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
  >
    {icon}
    <span className="ml-3 flex-grow text-left">{label}</span>
    {isPremium && <span className="text-xs font-bold text-yellow-500 dark:text-yellow-400 bg-yellow-100 dark:bg-yellow-900 dark:bg-opacity-50 px-2 py-0.5 rounded-full">PRO</span>}
  </button>
);

export default function LeftSidebar({
  sources,
  onFileUpload,
  onSelectSource,
  onDeleteSource,
  selectedSource,
  activeView,
  setActiveView,
  userTier,
  onUpgradeClick,
  theme,
  toggleTheme,
  isAuthenticated,
  onLoginClick,
  onLogout,
}: LeftSidebarProps) {

  const handleSearchClick = () => {
    if (isAuthenticated && userTier === 'premium') {
      setActiveView('search');
    } else {
      onUpgradeClick();
    }
  };

  const handleAddSourceClick = (event: React.MouseEvent<HTMLLabelElement>) => {
    if (!isAuthenticated) {
      event.preventDefault();
      onLoginClick();
    }
  };

  const handleDeleteClick = (e: React.MouseEvent, source: Source) => {
    e.stopPropagation();
    if (window.confirm(`Are you sure you want to delete "${source.name}"?`)) {
        onDeleteSource(source.id);
    }
  };

  return (
    <aside className="w-80 bg-white dark:bg-gray-800 p-4 flex flex-col h-full border-r border-gray-200 dark:border-gray-700 shadow-xl">
      <div className="flex items-center mb-6">
        <svg className="w-8 h-8 text-indigo-500 dark:text-indigo-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z" />
        </svg>
        <div className="ml-2">
          <h1 className="text-xl font-bold text-gray-900 dark:text-white">StudyLM</h1>
          <p className="text-xs text-gray-500 dark:text-gray-400 -mt-1">powered by Gemini Pro 2.5</p>
        </div>
      </div>

      <div className="mb-4">
        <label
          htmlFor="file-upload"
          onClick={handleAddSourceClick}
          className="w-full text-center px-4 py-2 bg-indigo-600 text-white rounded-md cursor-pointer hover:bg-indigo-700 transition-colors duration-200 block font-semibold"
        >
          + Add Source
        </label>
        <input id="file-upload" type="file" className="hidden" onChange={onFileUpload} accept=".txt,.md" />
      </div>

      <div className="flex-grow overflow-y-auto pr-2 -mr-2">
        <h2 className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-2">Sources</h2>
        <ul className="space-y-1">
          {sources.map(source => (
            <li key={source.id} className="group relative flex items-center">
              <button
                onClick={() => onSelectSource(source)}
                className={`flex-grow text-left px-3 py-2 rounded-md text-sm transition-colors duration-200 truncate ${
                  selectedSource?.id === source.id ? 'bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white font-semibold' : 'text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
                }`}
              >
                {source.name}
              </button>
              {!source.id.startsWith('sample-') && (
                <button 
                  onClick={(e) => handleDeleteClick(e, source)}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1 rounded-full text-gray-400 hover:bg-red-500 hover:text-white opacity-0 group-hover:opacity-100 transition-opacity focus:opacity-100"
                  aria-label={`Delete ${source.name}`}
                >
                  <TrashIcon/>
                </button>
              )}
            </li>
          ))}
        </ul>
      </div>

      <div className="mt-auto">
        <h2 className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-2">Tools</h2>
        <nav className="space-y-2">
            <NavItem icon={<SearchIcon />} label="AI Search" isActive={activeView === 'search'} onClick={handleSearchClick} isPremium={!isAuthenticated || userTier === 'free'} />
            <NavItem icon={<DocIcon />} label="View Source" isActive={activeView === 'source'} onClick={() => setActiveView('source')} disabled={!selectedSource} />
            <NavItem icon={<PlanIcon />} label="Revision Plan" isActive={activeView === 'plan'} onClick={() => setActiveView('plan')} disabled={!selectedSource} />
            <NavItem icon={<FlashcardIcon />} label="Flashcards" isActive={activeView === 'flashcards'} onClick={() => setActiveView('flashcards')} disabled={!selectedSource} />
            <NavItem icon={<QuizIcon />} label="AI Quiz" isActive={activeView === 'quiz'} onClick={() => setActiveView('quiz')} disabled={!selectedSource} />
        </nav>
        <div className="mt-6 pt-4 border-t border-gray-200 dark:border-gray-700">
            {isAuthenticated && (
              <div className="bg-gray-200 dark:bg-gray-700 rounded-lg p-3 text-center flex-grow mb-4">
                  <p className="text-sm font-medium text-gray-900 dark:text-white">
                      Tier: <span className={`font-bold ${userTier === 'premium' ? 'text-yellow-600 dark:text-yellow-400' : 'text-gray-600 dark:text-gray-300'}`}>{userTier.charAt(0).toUpperCase() + userTier.slice(1)}</span>
                  </p>
                  {userTier === 'free' && (
                      <button onClick={onUpgradeClick} className="mt-2 w-full text-sm bg-yellow-500 text-gray-900 font-bold py-1 px-3 rounded-md hover:bg-yellow-400 transition-colors duration-200">
                          Upgrade Now
                      </button>
                  )}
              </div>
            )}
            <div className="flex items-center justify-between">
                {isAuthenticated ? (
                  <button onClick={onLogout} className="flex items-center text-sm text-gray-500 dark:text-gray-400 hover:text-red-500 dark:hover:text-red-400 font-semibold transition-colors">
                      <LogoutIcon />
                      <span className="ml-2">Logout</span>
                  </button>
                ) : (
                  <button onClick={onLoginClick} className="flex-grow flex items-center justify-center text-sm text-white bg-indigo-600 hover:bg-indigo-700 font-semibold transition-colors py-2 px-4 rounded-md">
                      <LoginIcon />
                      <span className="ml-2">Login / Sign Up</span>
                  </button>
                )}
                <button onClick={toggleTheme} className="p-2 ml-4 rounded-full text-gray-500 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors">
                    {theme === 'light' ? <MoonIcon /> : <SunIcon />}
                </button>
            </div>
        </div>
      </div>
    </aside>
